import React, { useState, useEffect } from 'react';
import { Card, Row, Col, Badge, ProgressBar, Alert, ListGroup } from 'react-bootstrap';
import { 
  FileText, 
  Users, 
  Store, 
  CheckCircle, 
  XCircle, 
  AlertTriangle, 
  TrendingUp,
  AlertCircle,
  Clock,
  Target,
  ChevronRight,
  ChevronDown
} from 'lucide-react';
import { searchDocuments } from '../api';
import './ComplianceDashboard.css';

const ComplianceDashboard = () => {
  const [loading, setLoading] = useState(true);
  const [selectedStore, setSelectedStore] = useState(null);
  const [selectedEmployee, setSelectedEmployee] = useState(null);
  const [showStoreList, setShowStoreList] = useState(true);
  const [showEmployeeList, setShowEmployeeList] = useState(true);
  const [dashboardData, setDashboardData] = useState({
    totalDocuments: 0,
    validDocuments: 0,
    expiringDocuments: 0,
    expiredDocuments: 0,
    missingDocuments: 0,
    totalEmployees: 10,
    employeesWithCompleteDocuments: 0,
    employeesWithPendingDocuments: 0,
    storeWiseData: [],
    employeeWiseData: [],
    complianceRate: 0
  });

  // Employee-Store mapping
  const employeeStoreMapping = [
    { id: 'EMP001', name: 'Rajesh Kumar', store: 'Store 1' },
    { id: 'EMP002', name: 'Priya Singh', store: 'Store 2' },
    { id: 'EMP003', name: 'Amit Patel', store: 'Store 3' },
    { id: 'EMP004', name: 'Sneha Reddy', store: 'Store 4' },
    { id: 'EMP005', name: 'Vikram Sharma', store: 'Store 5' },
    { id: 'EMP006', name: 'Anita Desai', store: 'Store 6' },
    { id: 'EMP007', name: 'Rahul Mehta', store: 'Store 7' },
    { id: 'EMP008', name: 'Kavita Joshi', store: 'Store 8' },
    { id: 'EMP009', name: 'Suresh Nair', store: 'Store 9' },
    { id: 'EMP010', name: 'Meera Nair', store: 'Store 10' },
  ];

  // Mandatory document types
  const mandatoryDocuments = [
    'ID Proof',
    'Address Proof',
    'Educational Certificate',
    'Employment Contract'
  ];

  useEffect(() => {
    loadDashboardData();
  }, []);

  const getStatusColor = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const expiry = new Date(expiryDate);
    expiry.setHours(0, 0, 0, 0);
    const daysUntilExpiry = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));
    
    if (daysUntilExpiry <= 0) return 'expired';
    if (daysUntilExpiry <= 30) return 'expiring';
    return 'valid';
  };

  const loadDashboardData = async () => {
    setLoading(true);
    try {
      const response = await searchDocuments({});
      if (response.data && response.data.data) {
        const documents = response.data.data.map(doc => {
          const employee = employeeStoreMapping.find(emp => emp.id === doc.employeeId);
          return {
            ...doc,
            store: doc.store || (employee ? employee.store : 'Unknown'),
            employeeName: doc.employeeName || (employee ? employee.name : 'Unknown'),
            status: getStatusColor(doc.expiryDate)
          };
        });

        // Calculate statistics
        const totalDocuments = documents.length;
        const validDocuments = documents.filter(doc => doc.status === 'valid').length;
        const expiringDocuments = documents.filter(doc => doc.status === 'expiring').length;
        const expiredDocuments = documents.filter(doc => doc.status === 'expired').length;

        // Calculate employee-wise data
        const employeeDocCounts = {};
        documents.forEach(doc => {
          if (!employeeDocCounts[doc.employeeId]) {
            const emp = employeeStoreMapping.find(e => e.id === doc.employeeId);
            employeeDocCounts[doc.employeeId] = {
              employeeId: doc.employeeId,
              employeeName: emp ? emp.name : 'Unknown',
              store: emp ? emp.store : 'Unknown',
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              mandatoryDocs: [],
              missingMandatory: []
            };
          }
          employeeDocCounts[doc.employeeId].totalDocs++;
          if (doc.status === 'valid') employeeDocCounts[doc.employeeId].validDocs++;
          if (doc.status === 'expired') employeeDocCounts[doc.employeeId].expiredDocs++;
          if (doc.status === 'expiring') employeeDocCounts[doc.employeeId].expiringDocs++;
          
          if (mandatoryDocuments.includes(doc.documentType)) {
            employeeDocCounts[doc.employeeId].mandatoryDocs.push(doc.documentType);
          }
        });

        // Calculate missing mandatory documents
        let totalMissingDocs = 0;
        Object.keys(employeeDocCounts).forEach(empId => {
          const missing = mandatoryDocuments.filter(
            docType => !employeeDocCounts[empId].mandatoryDocs.includes(docType)
          );
          employeeDocCounts[empId].missingMandatory = missing;
          totalMissingDocs += missing.length;
        });

        // Add employees with no documents
        employeeStoreMapping.forEach(emp => {
          if (!employeeDocCounts[emp.id]) {
            employeeDocCounts[emp.id] = {
              employeeId: emp.id,
              employeeName: emp.name,
              store: emp.store,
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              mandatoryDocs: [],
              missingMandatory: mandatoryDocuments
            };
            totalMissingDocs += mandatoryDocuments.length;
          }
        });

        const employeeWiseData = Object.values(employeeDocCounts);
        const employeesWithCompleteDocuments = employeeWiseData.filter(
          emp => emp.missingMandatory.length === 0 && emp.expiredDocs === 0
        ).length;
        const employeesWithPendingDocuments = employeeStoreMapping.length - employeesWithCompleteDocuments;

        // Calculate store-wise data
        const storeDocCounts = {};
        documents.forEach(doc => {
          if (!storeDocCounts[doc.store]) {
            storeDocCounts[doc.store] = {
              store: doc.store,
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              employees: new Set()
            };
          }
          storeDocCounts[doc.store].totalDocs++;
          if (doc.status === 'valid') storeDocCounts[doc.store].validDocs++;
          if (doc.status === 'expired') storeDocCounts[doc.store].expiredDocs++;
          if (doc.status === 'expiring') storeDocCounts[doc.store].expiringDocs++;
          storeDocCounts[doc.store].employees.add(doc.employeeId);
        });

        const storeWiseData = Object.values(storeDocCounts).map(store => ({
          ...store,
          employeeCount: store.employees.size,
          complianceRate: store.totalDocs > 0 
            ? Math.round((store.validDocs / store.totalDocs) * 100) 
            : 0
        }));

        // Sort by store name
        storeWiseData.sort((a, b) => {
          const numA = parseInt(a.store.replace('Store ', ''));
          const numB = parseInt(b.store.replace('Store ', ''));
          return numA - numB;
        });

        const complianceRate = totalDocuments > 0 
          ? Math.round((validDocuments / totalDocuments) * 100) 
          : 0;

        setDashboardData({
          totalDocuments,
          validDocuments,
          expiringDocuments,
          expiredDocuments,
          missingDocuments: totalMissingDocs,
          totalEmployees: employeeStoreMapping.length,
          employeesWithCompleteDocuments,
          employeesWithPendingDocuments,
          storeWiseData,
          employeeWiseData,
          complianceRate
        });
      }
    } catch (error) {
      console.error('Error loading dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleStoreClick = (storeName) => {
    setSelectedStore(storeName);
    setSelectedEmployee(null);
    // Scroll to store detail section
    setTimeout(() => {
      const element = document.getElementById('store-detail-section');
      if (element) {
        element.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    }, 100);
  };

  const handleEmployeeClick = (employee) => {
    setSelectedEmployee(employee);
  };

  if (loading) {
    return (
      <div className="text-center py-5">
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
        <p className="mt-3 text-muted">Loading compliance dashboard...</p>
      </div>
    );
  }

  return (
    <div className="compliance-dashboard-wrapper">
      {/* Sidebar */}
      <div className="compliance-sidebar">
        <Card className="sidebar-card border-0 shadow-sm mb-3">
          <Card.Header 
            className="sidebar-header"
            onClick={() => setShowStoreList(!showStoreList)}
            style={{ cursor: 'pointer' }}
          >
            <div className="d-flex justify-content-between align-items-center">
              <div className="d-flex align-items-center">
                <Store size={18} className="me-2" />
                <strong>Stores</strong>
              </div>
              {showStoreList ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
            </div>
          </Card.Header>
          {showStoreList && (
            <ListGroup variant="flush" className="sidebar-list">
              {dashboardData.storeWiseData.map((store, idx) => (
                <ListGroup.Item
                  key={idx}
                  action
                  active={selectedStore === store.store}
                  onClick={() => handleStoreClick(store.store)}
                  className="sidebar-list-item"
                >
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <div className="fw-bold">{store.store}</div>
                      <small className="text-muted">{store.employeeCount} Employees</small>
                    </div>
                    <Badge 
                      bg={store.complianceRate >= 80 ? 'success' : store.complianceRate >= 50 ? 'warning' : 'danger'}
                      className="sidebar-badge"
                    >
                      {store.complianceRate}%
                    </Badge>
                  </div>
                </ListGroup.Item>
              ))}
            </ListGroup>
          )}
        </Card>

        <Card className="sidebar-card border-0 shadow-sm">
          <Card.Header 
            className="sidebar-header"
            onClick={() => setShowEmployeeList(!showEmployeeList)}
            style={{ cursor: 'pointer' }}
          >
            <div className="d-flex justify-content-between align-items-center">
              <div className="d-flex align-items-center">
                <Users size={18} className="me-2" />
                <strong>Employees</strong>
              </div>
              {showEmployeeList ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
            </div>
          </Card.Header>
          {showEmployeeList && (
            <ListGroup variant="flush" className="sidebar-list">
              {dashboardData.employeeWiseData
                .sort((a, b) => b.missingMandatory.length - a.missingMandatory.length)
                .map((emp, idx) => {
                  const isCompliant = emp.missingMandatory.length === 0 && emp.expiredDocs === 0;
                  return (
                    <ListGroup.Item
                      key={idx}
                      action
                      onClick={() => handleEmployeeClick(emp)}
                      className="sidebar-list-item"
                    >
                      <div className="d-flex justify-content-between align-items-center">
                        <div className="flex-grow-1">
                          <div className="fw-bold text-truncate" style={{ maxWidth: '150px' }}>
                            {emp.employeeName}
                          </div>
                          <small className="text-muted">{emp.employeeId}</small>
                        </div>
                        {isCompliant ? (
                          <CheckCircle size={18} className="text-success" />
                        ) : (
                          <AlertTriangle size={18} className="text-warning" />
                        )}
                      </div>
                    </ListGroup.Item>
                  );
                })}
            </ListGroup>
          )}
        </Card>
      </div>

      {/* Main Content */}
      <div className="compliance-content">
        <div className="compliance-dashboard">
          {/* Header */}
          <Card className="mb-4 border-0 shadow-sm">
            <Card.Header className="bg-gradient-primary text-white">
              <h3 className="mb-1">
                <Target className="me-2" size={28} />
                Overall Compliance Dashboard
              </h3>
              <p className="mb-0 opacity-75">Real-time document compliance monitoring and analytics</p>
            </Card.Header>
          </Card>

          {/* Alert Banners */}
          {dashboardData.expiredDocuments > 0 && (
            <Alert variant="danger" className="mb-4">
              <XCircle className="me-2" size={20} />
              <strong>Critical:</strong> {dashboardData.expiredDocuments} document(s) have expired and require immediate renewal.
            </Alert>
          )}

          {dashboardData.missingDocuments > 0 && (
            <Alert variant="warning" className="mb-4">
              <AlertTriangle className="me-2" size={20} />
              <strong>Action Required:</strong> {dashboardData.missingDocuments} mandatory document(s) are missing across {dashboardData.employeesWithPendingDocuments} employee(s).
            </Alert>
          )}

          {/* Main Statistics Cards */}
          <Row className="mb-4">
            <Col md={3}>
              <Card className="stats-card border-0 shadow-sm h-100">
                <Card.Body>
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <div className="text-muted small mb-1">TOTAL DOCUMENTS</div>
                      <h2 className="mb-0 fw-bold text-primary">{dashboardData.totalDocuments}</h2>
                    </div>
                    <div className="stats-icon bg-primary">
                      <FileText size={24} />
                    </div>
                  </div>
                  <div className="mt-3">
                    <small className="text-muted">All uploaded documents</small>
                  </div>
                </Card.Body>
              </Card>
            </Col>

            <Col md={3}>
              <Card className="stats-card border-0 shadow-sm h-100">
                <Card.Body>
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <div className="text-muted small mb-1">VALID DOCUMENTS</div>
                      <h2 className="mb-0 fw-bold text-success">{dashboardData.validDocuments}</h2>
                    </div>
                    <div className="stats-icon bg-success">
                      <CheckCircle size={24} />
                    </div>
                  </div>
                  <div className="mt-3">
                    <small className="text-success">
                      {dashboardData.complianceRate}% compliance rate
                    </small>
                  </div>
                </Card.Body>
              </Card>
            </Col>

            <Col md={3}>
              <Card className="stats-card border-0 shadow-sm h-100">
                <Card.Body>
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <div className="text-muted small mb-1">EXPIRING SOON</div>
                      <h2 className="mb-0 fw-bold text-warning">{dashboardData.expiringDocuments}</h2>
                    </div>
                    <div className="stats-icon bg-warning">
                      <Clock size={24} />
                    </div>
                  </div>
                  <div className="mt-3">
                    <small className="text-warning">Within 30 days</small>
                  </div>
                </Card.Body>
              </Card>
            </Col>

            <Col md={3}>
              <Card className="stats-card border-0 shadow-sm h-100">
                <Card.Body>
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <div className="text-muted small mb-1">EXPIRED</div>
                      <h2 className="mb-0 fw-bold text-danger">{dashboardData.expiredDocuments}</h2>
                    </div>
                    <div className="stats-icon bg-danger">
                      <XCircle size={24} />
                    </div>
                  </div>
                  <div className="mt-3">
                    <small className="text-danger">Requires renewal</small>
                  </div>
                </Card.Body>
              </Card>
            </Col>
          </Row>

          {/* Employee & Missing Documents Statistics */}
          <Row className="mb-4">
            <Col md={4}>
              <Card className="stats-card border-0 shadow-sm h-100">
                <Card.Body>
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <div className="text-muted small mb-1">TOTAL EMPLOYEES</div>
                      <h2 className="mb-0 fw-bold text-info">{dashboardData.totalEmployees}</h2>
                    </div>
                    <div className="stats-icon bg-info">
                      <Users size={24} />
                    </div>
                  </div>
                  <div className="mt-3">
                    <small className="text-muted">Active employees</small>
                  </div>
                </Card.Body>
              </Card>
            </Col>

            <Col md={4}>
              <Card className="stats-card border-0 shadow-sm h-100">
                <Card.Body>
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <div className="text-muted small mb-1">COMPLETE COMPLIANCE</div>
                      <h2 className="mb-0 fw-bold text-success">{dashboardData.employeesWithCompleteDocuments}</h2>
                    </div>
                    <div className="stats-icon bg-success">
                      <CheckCircle size={24} />
                    </div>
                  </div>
                  <div className="mt-3">
                    <small className="text-success">
                      {Math.round((dashboardData.employeesWithCompleteDocuments / dashboardData.totalEmployees) * 100)}% employees
                    </small>
                  </div>
                </Card.Body>
              </Card>
            </Col>

            <Col md={4}>
              <Card className="stats-card border-0 shadow-sm h-100">
                <Card.Body>
                  <div className="d-flex justify-content-between align-items-start">
                    <div>
                      <div className="text-muted small mb-1">MISSING DOCUMENTS</div>
                      <h2 className="mb-0 fw-bold text-danger">{dashboardData.missingDocuments}</h2>
                    </div>
                    <div className="stats-icon bg-danger">
                      <AlertCircle size={24} />
                    </div>
                  </div>
                  <div className="mt-3">
                    <small className="text-danger">
                      {dashboardData.employeesWithPendingDocuments} employees affected
                    </small>
                  </div>
                </Card.Body>
              </Card>
            </Col>
          </Row>

          {/* Overall Compliance Progress */}
          <Card className="mb-4 border-0 shadow-sm">
            <Card.Header className="bg-white border-bottom">
              <h5 className="mb-0">
                <TrendingUp className="me-2" size={20} />
                Overall Compliance Rate
              </h5>
            </Card.Header>
            <Card.Body>
              <div className="mb-2 d-flex justify-content-between">
                <span className="fw-bold">Document Compliance</span>
                <span className="fw-bold">{dashboardData.complianceRate}%</span>
              </div>
              <ProgressBar 
                now={dashboardData.complianceRate} 
                variant={dashboardData.complianceRate >= 80 ? 'success' : dashboardData.complianceRate >= 50 ? 'warning' : 'danger'}
                style={{ height: '30px' }}
                label={`${dashboardData.complianceRate}%`}
              />
              <div className="mt-3">
                <Row>
                  <Col md={3}>
                    <div className="text-center">
                      <div className="text-success fw-bold h4">{dashboardData.validDocuments}</div>
                      <div className="text-muted small">Valid</div>
                    </div>
                  </Col>
                  <Col md={3}>
                    <div className="text-center">
                      <div className="text-warning fw-bold h4">{dashboardData.expiringDocuments}</div>
                      <div className="text-muted small">Expiring</div>
                    </div>
                  </Col>
                  <Col md={3}>
                    <div className="text-center">
                      <div className="text-danger fw-bold h4">{dashboardData.expiredDocuments}</div>
                      <div className="text-muted small">Expired</div>
                    </div>
                  </Col>
                  <Col md={3}>
                    <div className="text-center">
                      <div className="text-secondary fw-bold h4">{dashboardData.missingDocuments}</div>
                      <div className="text-muted small">Missing</div>
                    </div>
                  </Col>
                </Row>
              </div>
            </Card.Body>
          </Card>

          {/* Store-wise Summary - Card Grid */}
          <Card className="mb-4 border-0 shadow-sm">
            <Card.Header className="bg-white border-bottom">
              <h5 className="mb-0">
                <Store className="me-2" size={20} />
                Store-wise Document Summary
              </h5>
              <small className="text-muted">Click on any store to view employee details</small>
            </Card.Header>
            <Card.Body>
              {dashboardData.storeWiseData.length === 0 ? (
                <div className="text-center text-muted py-4">
                  No store data available
                </div>
              ) : (
                <Row>
                  {dashboardData.storeWiseData.map((store, idx) => (
                    <Col md={6} lg={4} key={idx} className="mb-3">
                      <Card 
                        className="store-card h-100 border-0 shadow-sm"
                        onClick={() => handleStoreClick(store.store)}
                        style={{ cursor: 'pointer' }}
                      >
                        <Card.Body>
                          <div className="d-flex justify-content-between align-items-start mb-3">
                            <div>
                              <h5 className="mb-1 fw-bold">{store.store}</h5>
                              <small className="text-muted">
                                <Users size={14} className="me-1" />
                                {store.employeeCount} Employees
                              </small>
                            </div>
                            <div className={`compliance-badge ${
                              store.complianceRate >= 80 ? 'badge-success' : 
                              store.complianceRate >= 50 ? 'badge-warning' : 
                              'badge-danger'
                            }`}>
                              {store.complianceRate}%
                            </div>
                          </div>
                          
                          <div className="store-stats mb-3">
                            <div className="stat-row">
                              <span className="stat-label">Total Documents</span>
                              <span className="stat-value fw-bold">{store.totalDocs}</span>
                            </div>
                            <div className="stat-row">
                              <span className="stat-label text-success">
                                <CheckCircle size={14} className="me-1" />
                                Valid
                              </span>
                              <span className="stat-value text-success fw-bold">{store.validDocs}</span>
                            </div>
                            <div className="stat-row">
                              <span className="stat-label text-warning">
                                <Clock size={14} className="me-1" />
                                Expiring Soon
                              </span>
                              <span className="stat-value text-warning fw-bold">{store.expiringDocs}</span>
                            </div>
                            <div className="stat-row">
                              <span className="stat-label text-danger">
                                <XCircle size={14} className="me-1" />
                                Expired
                              </span>
                              <span className="stat-value text-danger fw-bold">{store.expiredDocs}</span>
                            </div>
                          </div>
                          
                          <ProgressBar 
                            now={store.complianceRate} 
                            variant={store.complianceRate >= 80 ? 'success' : store.complianceRate >= 50 ? 'warning' : 'danger'}
                            style={{ height: '8px' }}
                            className="rounded-pill"
                          />
                        </Card.Body>
                      </Card>
                    </Col>
                  ))}
                </Row>
              )}
            </Card.Body>
          </Card>

          {/* Store Drill-Down Section */}
          {selectedStore && (
            <div id="store-detail-section">
              <Card className="mb-4 border-0 shadow-lg store-detail-modal">
                <Card.Header className="bg-gradient-primary text-white d-flex justify-content-between align-items-center">
                  <h5 className="mb-0">
                    <Store className="me-2" size={20} />
                    {selectedStore} - Employee Details
                  </h5>
                  <button 
                    className="btn btn-sm btn-light"
                    onClick={() => setSelectedStore(null)}
                  >
                    ✕ Close
                  </button>
                </Card.Header>
                <Card.Body>
                  <Row>
                    {dashboardData.employeeWiseData
                      .filter(emp => emp.store === selectedStore)
                      .sort((a, b) => b.missingMandatory.length - a.missingMandatory.length)
                      .map((emp, idx) => {
                        const isCompliant = emp.missingMandatory.length === 0 && emp.expiredDocs === 0;
                        return (
                          <Col md={6} lg={4} key={idx} className="mb-3">
                            <Card 
                              className="employee-card h-100 border-0 shadow-sm"
                              onClick={() => handleEmployeeClick(emp)}
                              style={{ cursor: 'pointer' }}
                            >
                              <Card.Body>
                                <div className="d-flex justify-content-between align-items-start mb-3">
                                  <div>
                                    <h6 className="mb-0 fw-bold">{emp.employeeName}</h6>
                                    <small className="text-muted">{emp.employeeId}</small>
                                  </div>
                                  {isCompliant ? (
                                    <Badge bg="success" className="d-flex align-items-center">
                                      <CheckCircle size={12} className="me-1" />
                                      Compliant
                                    </Badge>
                                  ) : (
                                    <Badge bg="warning" className="d-flex align-items-center">
                                      <AlertTriangle size={12} className="me-1" />
                                      Pending
                                    </Badge>
                                  )}
                                </div>
                                
                                <div className="employee-stats">
                                  <div className="stat-item">
                                    <FileText size={16} className="text-primary me-2" />
                                    <span className="stat-text">{emp.totalDocs} Total</span>
                                  </div>
                                  <div className="stat-item">
                                    <CheckCircle size={16} className="text-success me-2" />
                                    <span className="stat-text">{emp.validDocs} Valid</span>
                                  </div>
                                  {emp.expiringDocs > 0 && (
                                    <div className="stat-item">
                                      <Clock size={16} className="text-warning me-2" />
                                      <span className="stat-text">{emp.expiringDocs} Expiring</span>
                                    </div>
                                  )}
                                  {emp.expiredDocs > 0 && (
                                    <div className="stat-item">
                                      <XCircle size={16} className="text-danger me-2" />
                                      <span className="stat-text">{emp.expiredDocs} Expired</span>
                                    </div>
                                  )}
                                  {emp.missingMandatory.length > 0 && (
                                    <div className="stat-item">
                                      <AlertCircle size={16} className="text-danger me-2" />
                                      <span className="stat-text">{emp.missingMandatory.length} Missing</span>
                                    </div>
                                  )}
                                </div>
                              </Card.Body>
                            </Card>
                          </Col>
                        );
                      })}
                  </Row>
                </Card.Body>
              </Card>
            </div>
          )}

          {/* Employee-wise Compliance - Card Grid */}
          <Card className="border-0 shadow-sm">
            <Card.Header className="bg-white border-bottom">
              <h5 className="mb-0">
                <Users className="me-2" size={20} />
                Employee-wise Document Status
              </h5>
              <small className="text-muted">Click on any employee to view detailed document information</small>
            </Card.Header>
            <Card.Body>
              <Row>
                {dashboardData.employeeWiseData
                  .sort((a, b) => b.missingMandatory.length - a.missingMandatory.length)
                  .map((emp, idx) => {
                    const isCompliant = emp.missingMandatory.length === 0 && emp.expiredDocs === 0;
                    return (
                      <Col md={6} lg={4} xl={3} key={idx} className="mb-3">
                        <Card 
                          className={`employee-card h-100 border-0 shadow-sm ${!isCompliant ? 'border-warning-highlight' : ''}`}
                          onClick={() => handleEmployeeClick(emp)}
                          style={{ cursor: 'pointer' }}
                        >
                          <Card.Body>
                            <div className="d-flex justify-content-between align-items-start mb-2">
                              <div className="flex-grow-1">
                                <h6 className="mb-0 fw-bold text-truncate">{emp.employeeName}</h6>
                                <small className="text-muted d-block">{emp.employeeId}</small>
                                <Badge bg="secondary" className="mt-1">{emp.store}</Badge>
                              </div>
                              {isCompliant ? (
                                <CheckCircle size={24} className="text-success ms-2" />
                              ) : (
                                <AlertTriangle size={24} className="text-warning ms-2" />
                              )}
                            </div>
                            
                            <div className="employee-quick-stats mt-3">
                              <div className="d-flex justify-content-between mb-2">
                                <span className="small text-muted">Documents</span>
                                <span className="small fw-bold">{emp.totalDocs}</span>
                              </div>
                              <div className="d-flex gap-1 mb-2">
                                {emp.validDocs > 0 && (
                                  <Badge bg="success" className="flex-fill text-center py-1">
                                    {emp.validDocs} Valid
                                  </Badge>
                                )}
                                {emp.expiringDocs > 0 && (
                                  <Badge bg="warning" className="flex-fill text-center py-1">
                                    {emp.expiringDocs} Expiring
                                  </Badge>
                                )}
                              </div>
                              {(emp.expiredDocs > 0 || emp.missingMandatory.length > 0) && (
                                <div className="d-flex gap-1">
                                  {emp.expiredDocs > 0 && (
                                    <Badge bg="danger" className="flex-fill text-center py-1">
                                      {emp.expiredDocs} Expired
                                    </Badge>
                                  )}
                                  {emp.missingMandatory.length > 0 && (
                                    <Badge bg="danger" className="flex-fill text-center py-1">
                                      {emp.missingMandatory.length} Missing
                                    </Badge>
                                  )}
                                </div>
                              )}
                            </div>
                          </Card.Body>
                        </Card>
                      </Col>
                    );
                  })}
              </Row>
            </Card.Body>
          </Card>

          {/* Employee Detail Modal */}
          {selectedEmployee && (
            <div className="employee-detail-overlay" onClick={() => setSelectedEmployee(null)}>
              <Card 
                className="employee-detail-modal border-0 shadow-lg"
                onClick={(e) => e.stopPropagation()}
              >
                <Card.Header className="bg-gradient-primary text-white d-flex justify-content-between align-items-center">
                  <div>
                    <h5 className="mb-0">{selectedEmployee.employeeName}</h5>
                    <small className="opacity-75">{selectedEmployee.employeeId} • {selectedEmployee.store}</small>
                  </div>
                  <button 
                    className="btn btn-sm btn-light"
                    onClick={() => setSelectedEmployee(null)}
                  >
                    ✕ Close
                  </button>
                </Card.Header>
                <Card.Body>
                  <Row className="mb-4">
                    <Col md={3}>
                      <div className="text-center p-3 bg-light rounded">
                        <FileText size={24} className="text-primary mb-2" />
                        <div className="h4 mb-0">{selectedEmployee.totalDocs}</div>
                        <small className="text-muted">Total Docs</small>
                      </div>
                    </Col>
                    <Col md={3}>
                      <div className="text-center p-3 bg-light rounded">
                        <CheckCircle size={24} className="text-success mb-2" />
                        <div className="h4 mb-0">{selectedEmployee.validDocs}</div>
                        <small className="text-muted">Valid</small>
                      </div>
                    </Col>
                    <Col md={3}>
                      <div className="text-center p-3 bg-light rounded">
                        <Clock size={24} className="text-warning mb-2" />
                        <div className="h4 mb-0">{selectedEmployee.expiringDocs}</div>
                        <small className="text-muted">Expiring</small>
                      </div>
                    </Col>
                    <Col md={3}>
                      <div className="text-center p-3 bg-light rounded">
                        <XCircle size={24} className="text-danger mb-2" />
                        <div className="h4 mb-0">{selectedEmployee.expiredDocs}</div>
                        <small className="text-muted">Expired</small>
                      </div>
                    </Col>
                  </Row>

                  {selectedEmployee.missingMandatory.length > 0 && (
                    <Alert variant="danger" className="mb-3">
                      <AlertTriangle className="me-2" size={18} />
                      <strong>Missing Mandatory Documents:</strong>
                      <ul className="mb-0 mt-2">
                        {selectedEmployee.missingMandatory.map((doc, i) => (
                          <li key={i}>{doc}</li>
                        ))}
                      </ul>
                    </Alert>
                  )}

                  {selectedEmployee.expiredDocs > 0 && (
                    <Alert variant="warning">
                      <XCircle className="me-2" size={18} />
                      <strong>Action Required:</strong> {selectedEmployee.expiredDocs} document(s) have expired and need renewal.
                    </Alert>
                  )}

                  {selectedEmployee.missingMandatory.length === 0 && selectedEmployee.expiredDocs === 0 && (
                    <Alert variant="success">
                      <CheckCircle className="me-2" size={18} />
                      <strong>All Clear!</strong> This employee has all required documents and none are expired.
                    </Alert>
                  )}
                </Card.Body>
              </Card>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ComplianceDashboard;
